Исправит
ь:
func main() {
values := []int{1,2,3,4,5}
for _, val := range values {
val := val // Копируем переменную
go func() {
fmt.Println(val)
}()
}
time.Sleep(100 * time.Millisecond)
}
или
func main() {
values := []int{1,2,3,4,5}
for _, val := range values {
go func(val int) {
fmt.Println(val)
}(val)
}
time.Sleep(100 * time.Millisecond)
}
